private lemma bits2num_push_zero {w : ℕ} (args : Vector (ZMod p) w) :
    bits2num (args.push 0) = 2 * bits2num args := by
  unfold bits2num; aesop;

private lemma bits2num_push_one {w : ℕ} (args : Vector (ZMod p) w) :
    bits2num (args.push 1) = 1 + 2 * bits2num args := by
  -- By definition of `bits2num`, we can expand the expression for `bits2num (args.push 1)`.
  simp [bits2num]

private lemma assert_bits_push {w : ℕ} (args : Vector (ZMod p) w) (x : ZMod p) :
    assert_bits (args.push x) = (assert_bits args && (x == 0 ∨ x == 1)) := by
  -- By definition of `assert_bits`, we can split the vector into `args` and `x`.
  simp [assert_bits, Vector.all_push]

