private lemma binary_repr_exists : ∀ (w : ℕ) (v : ℕ), v < 2 ^ w →
    ∃ args : Vector (ZMod p) w, assert_bits args = true ∧ bits2num args = (v : ZMod p) := by
  intro w;
  induction w <;> simp_all +decide [ pow_succ' ];
  · exact ⟨Vector.ofFn fun _ => 0, by simp [assert_bits, bits2num], by simp [bits2num, Vector.foldl]⟩;
  · intro v hv
    by_cases hv_even : Even v;
    · obtain ⟨ k, rfl ⟩ := hv_even; simp_all +decide [ Nat.mul_succ, pow_succ' ] ;
      obtain ⟨ args, h₁, h₂ ⟩ := ‹∀ v < 2 ^ _, ∃ args : Vector ( ZMod p ) _, _› k ( by linarith ) ; use args.push 0; simp_all +decide [ bits2num_push_zero ] ; ring;
      simp_all +decide [ assert_bits_push ];
    · rcases Nat.even_or_odd' v with ⟨ k, rfl | rfl ⟩ <;> simp_all +decide [ parity_simps ];
      obtain ⟨ args, h₁, h₂ ⟩ := ‹∀ v < 2 ^ _, ∃ args : Vector ( ZMod p ) _, _› k ( by linarith ) ; use args.push 1; simp_all +decide [ bits2num_push_one ] ; ring;
      unfold assert_bits at *; aesop;

