lemma bits_good : ∀ (w : ℕ) (e : Exp (ZMod p) (ZMod p)),
  e.eval.val < 2 ^ w -> ∃ args : Vector (ZMod p) w, assert_bits args = true ∧ e.eval = bits2num args := by
